class TradeService {
    static let shared = TradeService()
    private let networkMonitor = NWPathMonitor()
    private let networkQueue = DispatchQueue(label: "NetworkMonitor")
    private var isConnected = false
    private var cancellables = Set<AnyCancellable>()
    
    private init() {
        monitorNetwork()
    }
    
    private func monitorNetwork() {
        networkMonitor.pathUpdateHandler = { [weak self] path in
            self?.isConnected = path.status == .satisfied
        }
        networkMonitor.start(queue: networkQueue)
    }
    
    func executeTrade(symbol: String, quantity: Int, price: Double, type: TradeType) -> AnyPublisher<TradeResult, Error> {
        guard isConnected else {
            return Fail(error: TradeError.noNetwork)
                .eraseToAnyPublisher()
        }
        
        let trade = Trade(symbol: symbol, quantity: quantity, price: price, type: type)
        return URLSession.shared.dataTaskPublisher(for: buildTradeRequest(trade))
            .map(\.data)
            .decode(type: TradeResult.self, decoder: JSONDecoder())
            .receive(on: DispatchQueue.main)
            .eraseToAnyPublisher()
    }
    
    private func buildTradeRequest(_ trade: Trade) -> URLRequest {
        var request = URLRequest(url: URL(string: "https://api.tradingplatform.com/trade")!)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.setValue("Bearer \(AuthManager.shared.token)", forHTTPHeaderField: "Authorization")
        
        let body = [
            "symbol": trade.symbol,
            "quantity": trade.quantity,
            "price": trade.price,
            "type": trade.type.rawValue
        ]
        
        request.httpBody = try? JSONSerialization.data(withJSONObject: body)
        return request
    }
}

enum TradeType: String, CaseIterable {
