class AuthManager {
    static let shared = AuthManager()
    private(set) var token: String = ""
    private let secureStorage = SecureStorage()
    
    func authenticate(username: String, password: String) -> AnyPublisher<Bool, Error> {
        let credentials = ["username": username, "password": password]
        return URLSession.shared.dataTaskPublisher(for: buildAuthRequest(credentials))
            .map(\.data)
            .decode(type: AuthResponse.self, decoder: JSONDecoder())
            .receive(on: DispatchQueue.main)
            .handleEvents(receiveOutput: { [weak self] response in
                self?.token = response.token
                self?.secureStorage.saveToken(response.token)
            })
            .map { _ in true }
            .eraseToAnyPublisher()
    }
    
    private func buildAuthRequest(_ credentials: [String: String]) -> URLRequest {
        var request = URLRequest(url: URL(string: "https://api.tradingplatform.com/auth/login")!)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        request.httpBody = try? JSONSerialization.data(withJSONObject: credentials)
        return request
    }
}

struct AuthResponse: Codable {
    let token: String
    let expires: Date
}

class SecureStorage {
    private let keychain = KeychainSwift()
    
    func saveToken(_ token: String) {
        keychain.set(token, forKey: "access_token")
    }
    
    func getToken() -> String? {
        return keychain.get("access_token")
    }
    
    func deleteToken() {
        keychain.delete("access_token")
    }
}

class PortfolioManager {
    static let shared = PortfolioManager()
    @Published var holdings: [PortfolioHolding] = []
    @Published var totalValue: Double = 0.0
    
    private init() {
        loadPortfolio()
    }
    
    func updatePortfolio(_ newHoldings: [PortfolioHolding]) {
        holdings = newHoldings
        totalValue = holdings.reduce(0) { $0 + ($1.quantity * $1.currentPrice) }
    }
    
    func addHolding(_ holding: PortfolioHolding) {
        if let index = holdings.firstIndex(where: { $0.symbol == holding.symbol }) {
            holdings[index].quantity += holding.quantity
        } else {
            holdings.append(holding)
        }
        totalValue = holdings.reduce(0) { $0 + ($1.quantity * $1.currentPrice) }
    }
    
    func removeHolding(symbol: String) {
        holdings.removeAll { $0.symbol == symbol }
        totalValue = holdings.reduce(0) { $0 + ($1.quantity * $1.currentPrice) }
    }
    
    private func loadPortfolio() {
        // Simulate loading from persistent storage
        holdings = [
            PortfolioHolding(symbol: "AAPL", quantity: 10, currentPrice: 150.0),
            PortfolioHolding(symbol: "GOOGL", quantity: 5, currentPrice: 2800.0)
        ]
        totalValue = holdings.reduce(0) { $0 + ($1.quantity * $1.currentPrice) }
    }
}

struct PortfolioHolding {
    let symbol: String
    var quantity: Int
    let currentPrice: Double
    let purchasePrice: Double
    let change: Double
    
    var currentValue: Double {
        return Double(quantity) * currentPrice
    }
    
    var profitLoss: Double {
        return (currentPrice - purchasePrice) * Double(quantity)
    }
}

class StockService {
    static let shared = StockService()
    private let cache = NSCache<NSString, StockData>()
    
    func fetchStockData(symbol: String) -> AnyPublisher<StockData, Error> {
        if let cached = cache.object(forKey: symbol as NSString) {
            return Just(cached)
                .setFailureType(to: Error.self)
                .eraseToAnyPublisher()
        }
        
        return URLSession.shared.dataTaskPublisher(for: buildStockRequest(symbol))
            .map(\.data)
            .decode(type: StockData.self, decoder: JSONDecoder())
            .receive(on: DispatchQueue.main)
            .handleEvents(receiveOutput: { [weak self] data in
                self?.cache.setObject(data, forKey: symbol as NSString)
            })
            .eraseToAnyPublisher()
    }
    
    private func buildStockRequest(_ symbol: String) -> URLRequest {
        var request = URLRequest(url: URL(string: "https://api.tradingplatform.com/stock/\(symbol)")!)
        request.httpMethod = "GET"
        request.setValue("Bearer \(AuthManager.shared.token)", forHTTPHeaderField: "Authorization")
        return request
    }
}

struct StockData: Codable {
    let symbol: String
    let price: Double
    let change: Double
    let changePercent: Double
    let volume: Int
    let marketCap: Double
    let peRatio: Double
    let dividendYield: Double
    let timestamp: Date
}

class TradeViewController: UIViewController {
    @IBOutlet weak var symbolTextField: UITextField!
    @IBOutlet weak var quantityTextField: UITextField!
    @IBOutlet weak var priceLabel: UILabel!
    @IBOutlet weak var buyButton: UIButton!
    @IBOutlet weak var sellButton: UIButton!
    @IBOutlet weak var statusLabel: UILabel!
    
    private var stockData: StockData?
    private var cancellables = Set<AnyCancellable>()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
        setupBindings()
    }
    
    private func setupUI() {
        buyButton.backgroundColor = .systemGreen
        sellButton.backgroundColor = .systemRed
        buyButton.layer.cornerRadius = 8
        sellButton.layer.cornerRadius = 8
        symbolTextField.delegate = self
        quantityTextField.delegate = self
    }
    
    private func setupBindings() {
        symbolTextField.addTarget(self, action: #selector(symbolChanged), for: .editingChanged)
        quantityTextField.addTarget(self, action: #selector(quantityChanged), for: .editingChanged)
    }
    
    @objc private func symbolChanged() {
        guard let symbol = symbolTextField.text, !symbol.isEmpty else { return }
        StockService.shared.fetchStockData(symbol: symbol)
            .sink(
                receiveCompletion: { [weak self] completion in
                    if case .failure(let error) = completion {
                        self?.statusLabel.text = error.localizedDescription
                    }
                },
                receiveValue: { [weak self] data in
                    self?.stockData = data
                    self?.priceLabel.text = "$\(data.price)"
                }
            )
            .store(in: &cancellables)
    }
    
    @objc private func quantityChanged() {
        guard let quantity = Int(quantityTextField.text ?? "0"),
              let price = stockData?.price else { return }
        let total = Double(quantity) * price
        statusLabel.text = "Total: $\(total)"
    }
    
    @IBAction func buyTapped(_ sender: UIButton) {
        executeTrade(type: .buy)
    }
    
    @IBAction func sellTapped(_ sender: UIButton) {
        executeTrade(type: .sell)
    }
    
    private func executeTrade(type: TradeType) {
        guard let symbol = symbolTextField.text,
              let quantity = Int(quantityTextField.text ?? "0"),
              let price = stockData?.price else {
            statusLabel.text = "Please enter valid values"
            return
        }
        
        TradeService.shared.executeTrade(symbol: symbol, quantity: quantity, price: price, type: type)
            .sink(
                receiveCompletion: { [weak self] completion in
                    if case .failure(let error) = completion {
                        self?.statusLabel.text = error.localizedDescription
                    }
                },
                receiveValue: { [weak self] result in
                    self?.statusLabel.text = "Trade executed: \(result.status.rawValue)"
                    self?.updatePortfolio(result)
                }
            )
            .store(in: &cancellables)
    }
    
    private func updatePortfolio(_ result: TradeResult) {
        let holding = PortfolioHolding(
            symbol: result.symbol,
            quantity: result.quantity,
            currentPrice: result.price,
            purchasePrice: result.price,
            change: 0.0
        )
        PortfolioManager.shared.addHolding(holding)
    }
}

