        tableView.dataSource = self
        tableView.register(UITableViewCell.self, forCellReuseIdentifier: "holdingCell")
    }
    
    private func setupBindings() {
        PortfolioManager.shared.$holdings
            .receive(on: DispatchQueue.main)
            .sink { [weak self] holdings in
                self?.holdings = holdings
                self?.tableView.reloadData()
            }
            .store(in: &cancellables)
        
        PortfolioManager.shared.$totalValue
            .receive(on: DispatchQueue.main)
            .sink { [weak self] value in
                self?.totalValueLabel.text = "Total Value: $\(value)"
            }
            .store(in: &cancellables)
    }
